import {
  BrowserRouter,
  Routes,
  Route,
  Navigate,
  Outlet,
  useNavigate,
} from "react-router-dom";
import { useState, createContext, useContext } from "react";

const AuthContext = createContext();

const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(
    JSON.parse(localStorage.getItem("user")) || null
  );

  const login = (data) => {
    localStorage.setItem("user", JSON.stringify(data));
    setUser(data);
  };

  const logout = () => {
    localStorage.removeItem("user");
    setUser(null);
  };

  return (
    <AuthContext.Provider value={{ user, login, logout }}>
      {children}
    </AuthContext.Provider>
  );
};

const useAuth = () => useContext(AuthContext);

const ProtectedRoute = ({ role }) => {
  const { user } = useAuth();

  if (!user) return <Navigate to="/login" />;

  if (role && user.role !== role) return <Navigate to="/" />;

  return <Outlet />;
};

const Home = () => {
  const { user } = useAuth();

  return (
    <>
      <nav style={{gap:"10px", display:"flex", flexDirection:"row", alignItems:"right", justifyContent:"center  ",with:"100%",maxHeight:"max-content"}}> 
        <a style={{marginRight:"auto", marginTop:"auto",padding:"5px"}}>Home Page</a>  
        {!user && <button style={{padding:"5px", maxHeight:"max-content",borderRadius:"15px"}} onClick={() => window.location.href = "/login"}>Login / Register</button>}
        {user && user.role === "client" && <button  style={{padding:" 5px", maxHeight:"max-content"}} onClick={() => window.location.href = "/client"}>Client Dashboard</button>}
        {user && user.role === "tasker" && <button  style={{padding:"5px", maxHeight:"max-content"}} onClick={() => window.location.href = "/tasker"}>Tasker Dashboard</button>}
        {user && user.role === "admin" && <button style={{padding:"5px", maxHeight:"max-content"}} onClick={() => window.location.href = "/admin"}>Admin Dashboard</button>}
      </nav>
      <div style={{ marginTop:"auto", alignItems:"center"}} className="search" >
        <input style={{ marginTop: "auto", display: "flex", justifyContent: "flex-end", alignItems: "center"
  }} placeholder="Search tasks..." /><button>Search</button>

      </div>
    </>
  );
};


function Login() {
  const { login } = useAuth();
  const navigate = useNavigate();

  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [role, setRole] = useState("client");

  const handleLogin = async () => {
    try {
      const res = await fetch("http://localhost:5000/api/auth/login", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({ email, password }),
      });

      const data = await res.json();

      if (res.ok) {
        // store role also (important)
        login({ ...data, email, role });

        // redirect based on role
        if (role === "client") navigate("/client");
        else if (role === "tasker") navigate("/tasker");
        else navigate("/admin");
      } else {
        alert(data.message);
      }
    } catch (err) {
      alert("Error logging in");
    }
  };

  return (
    <div>
      <h2>Login</h2>

      <input
        type="email"
        placeholder="Email"
        value={email}
        onChange={(e) => setEmail(e.target.value)} />

      <input
        type="password"
        placeholder="Password"
        value={password}
        onChange={(e) => setPassword(e.target.value)} />

      <select value={role} onChange={(e) => setRole(e.target.value)}>
        <option value="client">Client</option>
        <option value="tasker">Tasker</option>
        <option value="admin">Admin</option>
      </select>

      <button onClick={handleLogin}>Login</button>
    </div>
  );
}

const Client = () => <h2>Client Dashboard</h2>;
const Tasker = () => <h2>Tasker Dashboard</h2>;
const Admin = () => <h2>Admin Dashboard</h2>;

export default function App() {
  return (
    <AuthProvider>
      <BrowserRouter>
        <Routes>
          <Route path="/" element={<Home />} />
          <Route path="/login" element={<Login />} />

          <Route element={<ProtectedRoute role="client" />}>
            <Route path="/client" element={<Client />} />
          </Route>

          <Route element={<ProtectedRoute role="tasker" />}>
            <Route path="/tasker" element={<Tasker />} />
          </Route>

          <Route element={<ProtectedRoute role="admin" />}>
            <Route path="/admin" element={<Admin />} />
          </Route>
        </Routes>
      </BrowserRouter>
    </AuthProvider>
  );
}
